import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Stitch","description":"","frontmatter":{"title":"Stitch","slug":"stitch"},"headers":[],"relativePath":"marketer-hub/stitch.md","filePath":"marketer-hub/stitch.md"}'),i={name:"marketer-hub/stitch.md"};function n(h,e,s,c,l,d){return a(),o("div",null,[...e[0]||(e[0]=[r('<h2 id="stitch-webhooks" tabindex="-1">Stitch Webhooks <a class="header-anchor" href="#stitch-webhooks" aria-label="Permalink to &quot;Stitch Webhooks&quot;">​</a></h2><p><em>[Image: 533]</em>.png &quot;header2-1-1587756104876.png&quot;)</p><p>This guide will walk you through how to send your Branch data to <a href="https://www.stitchdata.com/" target="_blank" rel="noreferrer"><strong>Stitch</strong></a> using Branch Webhooks. Enabling this integration will result in automatically forwarding Branch events to Stitch.</p><div class="info custom-block"><p class="custom-block-title">Replication, Schema, Webhook URLs, &amp; Security</p><p>For additional information on Replication, Schema, Webhook URLs, &amp; Security, please follow <a href="https://www.stitchdata.com/docs/integrations/webhooks/branch" target="_blank" rel="noreferrer">Stitch&#39;s documentation</a>.</p></div><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><h3 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h3><ul><li>This guide requires you to have integrated the (Branch SDK)[<a href="https://help.branch.io/developers-hub/docs" target="_blank" rel="noreferrer">https://help.branch.io/developers-hub/docs</a>] in your mobile apps.</li><li>You also need to be a Stitch customer</li></ul><h3 id="_1-add-branch-as-a-stitch-data-source" tabindex="-1">1. Add Branch as a Stitch data source <a class="header-anchor" href="#_1-add-branch-as-a-stitch-data-source" aria-label="Permalink to &quot;1. Add Branch as a Stitch data source&quot;">​</a></h3><ol><li><a href="https://app.stitchdata.com/" target="_blank" rel="noreferrer">Sign into your Stitch account.</a></li><li>On the Stitch Dashboard page, click the <strong>Add Integration</strong> button.</li><li>Click the <strong>Branch</strong> icon.</li><li>Enter a name for the integration. This is the name that will display on the Stitch Dashboard for the integration; it’ll also be used to create the schema in your destination. For example, the name “Stitch Branch” would create a schema called stitch_branch in the destination. <strong>Note</strong>: Schema names cannot be changed after you save the integration.</li><li>Click <strong>Save Integration</strong>.</li></ol><h3 id="_2-generate-a-branch-webhook-url" tabindex="-1">2. Generate a Branch Webhook URL <a class="header-anchor" href="#_2-generate-a-branch-webhook-url" aria-label="Permalink to &quot;2. Generate a Branch Webhook URL&quot;">​</a></h3><p>Once Stitch has successfully saved and created the Branch integration, you’ll be redirected to a page that displays your Branch webhook URL and token (which is blurred in the image below):</p><p><em>[Image: 625]</em></p><p>Click the <strong>Copy</strong> button to copy it.</p><p><strong>Note that this particular URL won’t display in Stitch again once you click Continue</strong>. Think of this URL like you would your login or API credentials - <strong>keep it secret, keep it safe</strong>. You can, however, <a href="https://www.stitchdata.com/docs/integrations/webhooks/branch#webhook-urls-security" target="_blank" rel="noreferrer">generate another URL</a> should you need it.</p><p>Once you’ve copied your webhook URL, click <strong>Continue</strong> to wrap things up in Stitch.</p><h3 id="_3-set-up-webhooks-in-branch" tabindex="-1">3. Set up webhooks in Branch <a class="header-anchor" href="#_3-set-up-webhooks-in-branch" aria-label="Permalink to &quot;3. Set up webhooks in Branch&quot;">​</a></h3><ol><li><p>Log in to the <a href="https://branch.dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Navigate to <a href="https://branch.dashboard.branch.io/data-feeds/webhooks/" target="_blank" rel="noreferrer">Webhooks</a> in Data Feeds.</p></li><li><p>Add a new webhook</p></li><li><p>In the window that displays:</p><ul><li>Paste your Stitch-generated webhook URL in the URL field.</li><li>Leave the method (POST) as-is.</li><li>Set the notification frequency using the drop-down menu. You can choose to receive a webhook for every single event occurrence or only for the first time that event is triggered for a unique user.<br> -Set the <a href="https://dev.branch.io/getting-started/webhooks/guide/#event-trigger" target="_blank" rel="noreferrer">event trigger</a> using the drop-down menu.</li></ul></li><li><p>When finished, click the Add webhook button.</p></li></ol>',17)])])}const b=t(i,[["render",n]]);export{p as __pageData,b as default};
